function careme_icon( $name, $args = array() ) {
    $icon = careme_get_icon( $name );
    if ( ! empty( $args['class'] ) ) {
        $icon = str_replace( '<svg', '<svg class="' . esc_attr( $args['class'] ) . '"', $icon );
    }
    echo $icon; // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped
}
